-- Network governance layer. Stores commitments, aggregates, and policy receipts—not private participant models or raw evidence.
alter table public.hivemind_rebate_ledger drop constraint if exists hivemind_rebate_ledger_event_type_check;
alter table public.hivemind_rebate_ledger add constraint hivemind_rebate_ledger_event_type_check check(event_type in('verified_reuse','quality_bonus','negative_evidence_reward','reversal','settlement'));
create table if not exists public.hivemind_causal_clearing_rounds(id uuid primary key default gen_random_uuid(), metric_key text not null, cohort_key text not null, minimum_participants int not null default 5 check(minimum_participants>=3), participant_count int not null default 0, aggregate_treatment numeric, aggregate_control numeric, aggregate_effect numeric, confidence numeric check(confidence between 0 and 1), commitments jsonb not null default '[]', privacy_policy jsonb not null, status text not null default 'collecting' check(status in('collecting','ready','cleared','cancelled')), clearing_digest text unique, created_at timestamptz not null default now(), cleared_at timestamptz);
create table if not exists public.hivemind_causal_clearing_contributions(id uuid primary key default gen_random_uuid(), round_id uuid not null references public.hivemind_causal_clearing_rounds(id) on delete cascade, organization_id uuid not null references public.orchestrator_organizations(id) on delete cascade, encrypted_commitment text not null, aggregate_input jsonb not null, input_digest text not null, created_at timestamptz not null default now(), unique(round_id,organization_id));
create table if not exists public.hivemind_executable_licenses(id uuid primary key default gen_random_uuid(), escrow_id uuid not null references public.hivemind_capability_escrows(id) on delete cascade, licensor_organization_id uuid not null references public.orchestrator_organizations(id), licensee_organization_id uuid not null references public.orchestrator_organizations(id), scopes text[] not null, execution_limits jsonb not null, economics jsonb not null, policy_ast jsonb not null, starts_at timestamptz not null default now(), expires_at timestamptz not null, status text not null default 'proposed' check(status in('proposed','active','suspended','expired','revoked')), license_digest text not null unique, created_at timestamptz not null default now());
create table if not exists public.hivemind_systemic_risk_snapshots(id uuid primary key default gen_random_uuid(), organization_id uuid references public.orchestrator_organizations(id) on delete cascade, nodes jsonb not null, edges jsonb not null, cascades jsonb not null, concentration_score int not null check(concentration_score between 0 and 100), recommended_hedges jsonb not null, snapshot_digest text not null unique, created_at timestamptz not null default now());
create table if not exists public.hivemind_value_attributions(id uuid primary key default gen_random_uuid(), settlement_id uuid not null references public.hivemind_causal_settlements(id) on delete cascade, participant_type text not null, participant_ref text not null, organization_id uuid references public.orchestrator_organizations(id), causal_weight numeric not null check(causal_weight between 0 and 1), credit_cents bigint not null default 0, rationale jsonb not null, created_at timestamptz not null default now(), unique(settlement_id,participant_type,participant_ref));
create table if not exists public.hivemind_privacy_futures(id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.orchestrator_organizations(id) on delete cascade, proposed_disclosure jsonb not null, scenarios jsonb not null, option_value_score int not null check(option_value_score between 0 and 100), recommendation text not null, forecast_digest text not null unique, created_by uuid references auth.users(id), created_at timestamptz not null default now());
create table if not exists public.hivemind_negative_evidence(id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.orchestrator_organizations(id) on delete cascade, problem_class text not null, attempted_pattern text not null, boundary_conditions jsonb not null, aggregate_result jsonb not null, verification jsonb not null, disclosure_receipt_id uuid references public.hivemind_disclosure_receipts(id), evidence_digest text not null unique, status text not null default 'candidate' check(status in('candidate','verified','published','retracted')), prevented_repetition_count int not null default 0, reward_cents bigint not null default 0, created_at timestamptz not null default now());
create table if not exists public.hivemind_lineage_events(id uuid primary key default gen_random_uuid(), contribution_id uuid not null references public.hivemind_capability_contributions(id) on delete cascade, parent_event_id uuid references public.hivemind_lineage_events(id), event_type text not null check(event_type in('origin','adaptation','verification','negative_evidence','improvement','deprecation')), anonymous_actor text not null, change_summary text not null, evidence_refs jsonb not null default '{}', event_digest text not null unique, created_at timestamptz not null default now());
create table if not exists public.hivemind_governance_proposals(id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.orchestrator_organizations(id), title text not null, rationale text not null, policy_domain text not null, proposed_policy jsonb not null, cade_assessment jsonb not null, voting_policy jsonb not null, status text not null default 'draft' check(status in('draft','open','accepted','rejected','enacted','expired')), opens_at timestamptz, closes_at timestamptz, proposal_digest text not null unique, created_by uuid references auth.users(id), created_at timestamptz not null default now());
create table if not exists public.hivemind_governance_votes(id uuid primary key default gen_random_uuid(), proposal_id uuid not null references public.hivemind_governance_proposals(id) on delete cascade, organization_id uuid not null references public.orchestrator_organizations(id), vote text not null check(vote in('support','oppose','abstain')), weight numeric not null default 1 check(weight>0 and weight<=10), rationale_digest text, created_at timestamptz not null default now(), unique(proposal_id,organization_id));
create table if not exists public.hivemind_execution_bundles(id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.orchestrator_organizations(id) on delete cascade, opportunity_id uuid references public.hivemind_opportunities(id) on delete set null, objective text not null, steps jsonb not null, gates jsonb not null, rollback_plan jsonb not null, current_step text not null default 'disclosure', status text not null default 'draft' check(status in('draft','approval_required','queued','executing','verified','rolled_back','cancelled')), task_id uuid references public.tasks(id), bundle_digest text not null unique, created_by uuid references auth.users(id), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create index if not exists idx_hive_clearing_status on public.hivemind_causal_clearing_rounds(status,created_at desc); create index if not exists idx_hive_lineage_contribution on public.hivemind_lineage_events(contribution_id,created_at); create index if not exists idx_hive_governance_status on public.hivemind_governance_proposals(status,closes_at); create index if not exists idx_hive_bundles_org on public.hivemind_execution_bundles(organization_id,status,created_at desc);
alter table public.hivemind_causal_clearing_rounds enable row level security; alter table public.hivemind_causal_clearing_contributions enable row level security; alter table public.hivemind_executable_licenses enable row level security; alter table public.hivemind_systemic_risk_snapshots enable row level security; alter table public.hivemind_value_attributions enable row level security; alter table public.hivemind_privacy_futures enable row level security; alter table public.hivemind_negative_evidence enable row level security; alter table public.hivemind_lineage_events enable row level security; alter table public.hivemind_governance_proposals enable row level security; alter table public.hivemind_governance_votes enable row level security; alter table public.hivemind_execution_bundles enable row level security;
